use std::thread;
use std::marker::PhantomData;
use std::sync::atomic::{AtomicI32, Ordering};
use std::sync::Arc;

// Better design: use Arc<AtomicI32> for actual thread-safe shared state
struct Handle {
    inner: Arc<AtomicI32>,
    _marker: PhantomData<i32>,  // purely illustrative here; Arc already is Send+Sync
}

impl Handle {
    fn new(value: i32) -> Self {
        Handle {
            inner: Arc::new(AtomicI32::new(value)),
            _marker: PhantomData,
        }
    }
}

fn main() {
    let handle = Handle::new(42);
    let handle2 = Handle { inner: Arc::clone(&handle.inner), _marker: PhantomData };
    let t = std::thread::spawn(move || {
        println!("value = {}", handle2.inner.load(Ordering::Relaxed));
    });
    t.join().unwrap();
}

