fixed_code:
use std::marker::PhantomData;

// PhantomData<fn(&'scope ()) -> &'scope ()> gives Token invariance over 'scope
// PhantomData<&'scope ()> is simpler for a covariant brand
struct Token<'scope> {
    _brand: PhantomData<&'scope ()>,
}

fn with_token<F, R>(f: F) -> R
where
    F: for<'s> FnOnce(Token<'s>) -> R,
{
    f(Token { _brand: PhantomData })
}

fn use_token(_t: Token<'_>) {
    println!("operating with valid token");
}

fn main() {
    with_token(|tok| use_token(tok));
    // Tokens cannot be forged outside `with_token` because the constructor is private
    // and Token<'_> cannot be named by the caller.
}

